const d = new Date();
const day = d.getDay();
const diff = day === 0 ? -6 : 1 - day;
d.setDate(d.getDate() + diff);
const weekStart = d.toISOString().split('T')[0];

return $input.all().map(item => ({
  json: { ...item.json, weekStart }
}));

const topic = $input.first().json;
const items = [];

for (const url of (topic.rssUrls || [])) {
  items.push({
    json: {
      feedUrl: url,
      feedType: 'rss',
      topicId: topic._id,
      topicName: topic.name,
      topicRecipients: topic.recipients,
      weekStart: topic.weekStart
    }
  });
}

for (const keyword of (topic.keywords || [])) {
  items.push({
    json: {
      feedUrl: `https://www.bing.com/news/search?q=${encodeURIComponent(keyword)}&format=RSS&setlang=fr&cc=FR`,
      feedType: 'bing_news',
      keyword,
      topicId: topic._id,
      topicName: topic.name,
      topicRecipients: topic.recipients,
      weekStart: topic.weekStart
    }
  });
}

if (topic.customQuery) {
  items.push({
    json: {
      feedUrl: `https://www.bing.com/news/search?q=${encodeURIComponent(topic.customQuery)}&format=RSS&setlang=fr&cc=FR`,
      feedType: 'bing_news',
      keyword: topic.customQuery,
      topicId: topic._id,
      topicName: topic.name,
      topicRecipients: topic.recipients,
      weekStart: topic.weekStart
    }
  });
}

return items;

const topic = $('Loop Over Items').first().json;
const allArticles = [];

for (const inputItem of $input.all()) {
  if (inputItem.json.error) continue;
  const xmlText = inputItem.json.data || '';
  if (!xmlText || typeof xmlText !== 'string') continue;

  // Try to infer a base URL from the channel <link> for relative URL resolution
  let baseUrl = '';
  const chanLink = xmlText.match(/<link>\s*(https?:\/\/[^<]+?)\s*<\/link>/);
  if (chanLink) {
    try { baseUrl = new URL(chanLink[1]).origin; } catch(e) {}
  }

  const itemRegex = /<item>([\s\S]*?)<\/item>|<entry>([\s\S]*?)<\/entry>/g;
  let match;
  while ((match = itemRegex.exec(xmlText)) !== null) {
    const itemXml = match[1] || match[2];

    const getTag = (tag) => {
      const m = itemXml.match(new RegExp(`<${tag}(?:[^>]*)>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/${tag}>`));
      return m ? m[1].trim() : '';
    };

    const title = getTag('title');
    let url = getTag('link');
    if (!url) {
      const m = itemXml.match(/<link[^>]*href="([^"]+)"/);
      url = m ? m[1] : getTag('guid');
    }

    // Resolve relative URLs using channel base
    if (url && !url.startsWith('http') && baseUrl) {
      try { url = new URL(url, baseUrl).href; } catch(e) {}
    }

    const pubDate = getTag('pubDate') || getTag('published') || getTag('updated') || getTag('dc:date');
    const content = (getTag('description') || getTag('summary') || '').replace(/<[^>]+>/g, '').slice(0, 500);

    if (!title || !url) continue;

    let source = '';
    try { source = new URL(url).hostname.replace('www.', ''); } catch(e) { source = 'unknown'; }

    allArticles.push({
      json: { title, url, pubDate, content, source, topicId: topic._id, topicName: topic.name, topicRecipients: topic.recipients, weekStart: topic.weekStart }
    });
  }
}

return allArticles;

const seen = new Set();
return $input.all().filter(item => {
  const url = item.json.url;
  if (!url || seen.has(url)) return false;
  seen.add(url);
  return true;
}).map(item => ({ json: item.json }));

const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
return $input.all().filter(item => {
  const raw = item.json.pubDate;
  if (!raw) return true; // no date → assume recent, keep it
  const pub = new Date(raw).getTime();
  if (isNaN(pub)) return true; // unparseable → assume recent, keep it
  return pub >= sevenDaysAgo;
}).map(item => ({ json: item.json }));

return $input.all()
  .sort((a, b) => new Date(b.json.pubDate) - new Date(a.json.pubDate))
  .slice(0, 30)
  .map(item => ({ json: item.json }));

const articles = $input.all().map(i => i.json);
const topic = $('Loop Over Items').first().json;

if (articles.length === 0) {
  throw new Error(`Aucun article trouvé pour le sujet "${topic.name}" cette semaine.`);
}

const articleList = articles.map((a, i) =>
  `[${i+1}] TITRE: ${a.title}\nSOURCE: ${a.source}\nDATE: ${a.pubDate}\nURL: ${a.url}`
).join('\n\n---\n\n');

return [{
  json: {
    topicId: topic._id,
    topicName: topic.name,
    topicRecipients: topic.recipients,
    weekStart: topic.weekStart,
    articleCount: articles.length,
    articleList,
    rawArticles: articles
  }
}];

const d = $input.first().json;
const requestBody = {
  model: 'gpt-5-mini',

  max_completion_tokens: 16000,
  messages: [
    {
      role: 'system',
      content: 'Tu es un analyste expert en veille stratégique, spécialisé dans le domaine "' + d.topicName + '". Tu dois TOUJOURS répondre avec un JSON valide, sans markdown, sans commentaire, uniquement le JSON brut.'
    },
    {
      role: 'user',
      content: 'Voici ' + d.articleCount + ' articles collectés cette semaine sur le sujet "' + d.topicName + '".\n\n' + d.articleList + '\n\nAnalyse ces articles et réponds UNIQUEMENT avec ce JSON (pas de markdown, juste le JSON brut) :\n\n{"synthesis": "Synthèse executive en 5-7 phrases sur les tendances clés de la semaine.", "articles": [{"title": "titre exact", "url": "url exacte", "source": "nom de la source", "category": "Stratégie|Innovation|Marchés|Réglementation|International|Autre", "summary": "résumé en 1 phrase"}]}\n\nRègles : inclus TOUS les articles, hors sujet = category Autre, n invente rien.'
    }
  ]
};

return [{
  json: {
    topicId: d.topicId,
    topicName: d.topicName,
    topicRecipients: d.topicRecipients,
    weekStart: d.weekStart,
    articleCount: d.articleCount,
    rawArticles: d.rawArticles,
    requestBody
  }
}];

const openAiResponse = $input.first().json;
const topic = $('Prepare OpenAI Body').first().json;
const raw = openAiResponse.choices?.[0]?.message?.content
  || openAiResponse.message?.content
  || openAiResponse.text
  || '';

if (!raw) throw new Error('LLM_EMPTY_RESPONSE');

let parsed;
try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim()
    .replace(/\\(?!["\\\/bfnrtu])/g, '\\\\');
  try {
    parsed = JSON.parse(cleaned);
  } catch (e1) {
    let repaired = '';
    let inString = false;
    let i = 0;
    while (i < cleaned.length) {
      const ch = cleaned[i];
      if (ch === '\\' && inString) {
        repaired += ch + (cleaned[i + 1] || '');
        i += 2;
        continue;
      }
      if (ch === '"') {
        if (!inString) {
          inString = true;
          repaired += ch;
        } else {
          let j = i + 1;
          while (j < cleaned.length && cleaned[j] === ' ') j++;
          const next = cleaned[j];
          if (next === ':' || next === ',' || next === '}' || next === ']' || j >= cleaned.length) {
            inString = false;
            repaired += ch;
          } else {
            repaired += '\\"';
          }
        }
      } else {
        repaired += ch;
      }
      i++;
    }
    parsed = JSON.parse(repaired);
  }
} catch (e) {
  throw new Error('LLM_PARSE_ERROR: ' + e.message + ' | Debut: ' + raw.slice(0, 300));
}

if (!parsed.synthesis || !Array.isArray(parsed.articles)) {
  throw new Error('LLM_STRUCTURE_ERROR: synthesis ou articles manquants');
}

return [{
  json: {
    topicId: topic.topicId,
    topicName: topic.topicName,
    topicRecipients: topic.topicRecipients,
    weekStart: topic.weekStart,
    synthesis: parsed.synthesis,
    articles: parsed.articles,
    generatedAt: Date.now()
  }
}];

const data = $('Parse LLM Output').first().json;
const weekLabel = new Date(data.weekStart).toLocaleDateString('fr-FR', {
  day: 'numeric', month: 'long', year: 'numeric'
});

const categoryOrder = ['Stratégie', 'Innovation', 'Marchés', 'Réglementation', 'International', 'Autre'];
const byCategory = {};
for (const article of data.articles) {
  const cat = article.category || 'Autre';
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(article);
}

const categoryBlocks = categoryOrder
  .filter(cat => byCategory[cat])
  .map(cat => {
    const items = byCategory[cat].map(a =>
      '<div style="margin-bottom:14px;padding-bottom:14px;border-bottom:1px solid #f0f0f0;">'
      + '<a href="' + a.url + '" style="color:#C0272D;font-weight:600;text-decoration:none;font-size:14px;">' + a.title + '</a><br>'
      + '<span style="color:#999;font-size:12px;">' + a.source + '</span>'
      + '<p style="margin:6px 0 0;color:#555;font-size:13px;line-height:1.6;">' + a.summary + '</p>'
      + '</div>'
    ).join('');
    return '<div style="font-size:11px;font-weight:700;color:#C0272D;text-transform:uppercase;letter-spacing:1.5px;border-bottom:2px solid #C0272D;padding-bottom:5px;margin:24px 0 12px;">' + cat + '</div>' + items;
  }).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f2f2f2;font-family:Arial,Helvetica,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f2f2f2;"><tr><td align="center" style="padding:24px 16px;">
<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#ffffff;">
<tr><td style="background:#C0272D;padding:32px 40px;text-align:center;">
  <img src="data:image/png;base64," alt="Schmidt Groupe" style="max-height:70px;width:auto;" />
  <div style="height:1px;background:rgba(255,255,255,0.25);margin:18px 0;"></div>
  <div style="color:#ffffff;font-size:18px;font-weight:600;">Veille ${data.topicName}</div>
  <div style="color:rgba(255,255,255,0.8);font-size:13px;margin-top:6px;">Semaine du ${weekLabel} &middot; ${data.articles.length} articles analysés</div>
</td></tr>
<tr><td style="padding:28px 36px 16px;">
  <div style="border-left:4px solid #C0272D;padding:14px 18px;background:#fdf5f5;">
    <div style="font-size:11px;font-weight:700;color:#C0272D;text-transform:uppercase;letter-spacing:1.5px;margin-bottom:8px;">Synthèse de la semaine</div>
    <div style="font-size:14px;line-height:1.75;color:#333;">${data.synthesis}</div>
  </div>
</td></tr>
<tr><td style="padding:0 36px 36px;">
  <div style="font-size:11px;font-weight:700;color:#C0272D;text-transform:uppercase;letter-spacing:1.5px;margin-bottom:16px;">Articles par catégorie</div>
  ${categoryBlocks}
</td></tr>
<tr><td style="background:#C0272D;padding:14px 36px;text-align:center;">
  <div style="color:rgba(255,255,255,0.7);font-size:11px;">Généré le ${new Date(data.generatedAt).toLocaleString('fr-FR')} &middot; Schmidt Groupe &middot; Veille Automatisée</div>
</td></tr>
</table>
</td></tr></table>
</body></html>`;

return [{
  json: {
    ...data,
    htmlEmail: html,
    subject: `[Veille ${data.topicName}] Semaine du ${weekLabel} — ${data.articles.length} articles`,
    to: data.topicRecipients || []
  }
}];

const crypto = require('crypto');
const data = $input.first().json;
const endpoint = $env.AZURE_COMMUNICATION_ENDPOINT;
const accessKey = $env.AZURE_COMMUNICATION_ACCESS_KEY;
const fromAddress = $env.AZURE_COMMUNICATION_FROM_ADDRESS;

const bodyObj = {
  senderAddress: fromAddress,
  content: { subject: data.subject, html: data.htmlEmail },
  recipients: { to: (data.to || []).map(addr => ({ address: addr })) }
};
const bodyStr = JSON.stringify(bodyObj);

const pathAndQuery = '/emails:send?api-version=2023-03-31';
const host = endpoint.replace(/^https?:\/\//, '').replace(/\/$/, '');
const fullUrl = endpoint.replace(/\/$/, '') + pathAndQuery;
const dateStr = new Date().toUTCString();

const contentHash = crypto.createHash('sha256').update(bodyStr).digest('base64');
const stringToSign = 'POST\n' + pathAndQuery + '\n' + dateStr + ';' + host + ';' + contentHash;
const signature = crypto.createHmac('sha256', Buffer.from(accessKey, 'base64')).update(stringToSign).digest('base64');
const authorization = 'HMAC-SHA256 SignedHeaders=date;host;x-ms-content-sha256&Signature=' + signature;

return [{ json: { ...data, _acsUrl: fullUrl, _acsBody: bodyStr, _acsDate: dateStr, _acsContentHash: contentHash, _acsAuthorization: authorization } }];
